+/* Scanline sweep effect for terminal blocks */
+@keyframes scanline-sweep {
+  0% {
+    transform: translateY(-100%);
+  }
+  100% {
+    transform: translateY(400%);
+  }
+}
+
+.group-scanline:hover .scanline-effect {
+  animation: scanline-sweep 1.2s ease-in-out;
+}
+
+/* Rotating conic-gradient border glow for strong terminal block */
+@keyframes border-rotate {
+  from {
+    --border-angle: 0deg;
+  }
+  to {
+    --border-angle: 360deg;
+  }
+}
+
+@property --border-angle {
+  syntax: "<angle>";
+  initial-value: 0deg;
+  inherits: false;
+}
+
+.animate-border-rotate {
+  animation: border-rotate 4s linear infinite;
+  border-image: conic-gradient(
+    from var(--border-angle),
+    rgba(16, 185, 129, 0.4),
+    rgba(16, 185, 129, 0.05) 30%,
+    rgba(16, 185, 129, 0.4) 50%,
+    rgba(16, 185, 129, 0.05) 70%,
+    rgba(16, 185, 129, 0.4)
+  ) 1;
+}
+
 /* Staggered animation delays */
